pub type EventMask = u32;
pub type ReadyMask = u32;

pub const EVENT_READ: EventMask = 0x01;
pub const EVENT_WRITE: EventMask = 0x02;
pub const EVENT_ERROR: EventMask = 0x04;
pub const EVENT_HUP: EventMask = 0x08;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Completion {
    Ready(ReadyMask),
    WouldBlock,
    Timeout,
    Interrupted,
    HangUp,
    Error(i32),
}

impl Completion {
    pub fn into_futex_result(self) -> Result<isize, Errno> {
        match self {
            Self::Ready(_) => Ok(0),
            Self::WouldBlock => Err(Errno::EAGAIN),
            Self::Timeout => Err(Errno::ETIMEDOUT),
            Self::Interrupted => Err(Errno::EINTR),
            Self::HangUp => Ok(0),
            Self::Error(_) => Err(Errno::EINVAL),
        }
    }

    pub fn into_io_ready_result(self) -> Result<(), Errno> {
        match self {
            Self::Ready(_) | Self::HangUp => Ok(()),
            Self::WouldBlock => Err(Errno::EAGAIN),
            Self::Timeout => Err(Errno::ETIMEDOUT),
            Self::Interrupted => Err(Errno::EINTR),
            Self::Error(_) => Err(Errno::EINVAL),
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct WaitPolicy {
    pub nonblock: bool,
    pub timeout: Option<Duration>,
    pub interruptible: bool,
    pub check_signal_before_poll: bool,
}

impl WaitPolicy {
    pub const fn blocking() -> Self {
        Self {
            nonblock: false,
            timeout: None,
            interruptible: true,
            check_signal_before_poll: true,
        }
    }

    pub const fn nonblocking() -> Self {
        Self {
            nonblock: true,
            timeout: None,
            interruptible: true,
            check_signal_before_poll: true,
        }
    }

    pub fn from_timeout(timeout: Option<Duration>) -> Self {
        Self {
            nonblock: timeout == Some(Duration::ZERO),
            timeout,
            interruptible: true,
            check_signal_before_poll: true,
        }
    }

    pub const fn with_interruptible(mut self, interruptible: bool) -> Self {
        self.interruptible = interruptible;
        self
    }

    pub const fn with_signal_check_before_poll(mut self, check_signal_before_poll: bool) -> Self {
        self.check_signal_before_poll = check_signal_before_poll;
        self
    }

    pub fn should_wait(&self) -> bool {
        !self.nonblock
    }

    pub fn timeout(&self) -> Option<Duration> {
        self.timeout
    }
}

pub async fn wait_with_policy<T>(
    task: &Arc<Task>,
    fut: impl Future<Output = T>,
    policy: WaitPolicy,
    sigmask: Option<SigSet>,
) -> SysResult<TimeLimitedType<T>> {
    wait_with_policy_and_wake(task, fut, policy, sigmask, None).await
}

pub async fn wait_with_policy_and_wake<T>(
    task: &Arc<Task>,
    fut: impl Future<Output = T>,
    policy: WaitPolicy,
    sigmask: Option<SigSet>,
    wake_set: Option<SigSet>,
) -> SysResult<TimeLimitedType<T>> {
    let fut = TimeLimitedFuture::new(fut, policy.timeout());
    if policy.interruptible {
        interruptable(
            task,
            fut,
            sigmask,
            wake_set,
            policy.check_signal_before_poll,
        )
        .await
    } else {
        Ok(fut.await)
    }
}

#[derive(Debug, Clone)]
pub enum WaitOutcome<T> {
    Ready(T),
    Timeout,
}

impl<T> WaitOutcome<T> {
    pub fn ready_or(self, timeout_value: T) -> T {
        match self {
            Self::Ready(value) => value,
            Self::Timeout => timeout_value,
        }
    }
}

pub async fn wait_outcome_with_policy<T>(
    task: &Arc<Task>,
    fut: impl Future<Output = T>,
    policy: WaitPolicy,
    sigmask: Option<SigSet>,
) -> SysResult<WaitOutcome<T>> {
    if !policy.should_wait() {
        return Ok(WaitOutcome::Ready(fut.await));
    }

    match wait_with_policy(task, fut, policy, sigmask).await? {
        TimeLimitedType::Ok(value) => Ok(WaitOutcome::Ready(value)),
        TimeLimitedType::TimeOut => Ok(WaitOutcome::Timeout),
    }
}

pub async fn sleep_with_policy(task: &Arc<Task>, interval: Duration) -> Duration {
    let expire = crate::time::gettime::get_time_duration() + interval;
    let policy = WaitPolicy::from_timeout(Some(interval));
    let _ = wait_with_policy(task, pending::<()>(), policy, None).await;
    let now = crate::time::gettime::get_time_duration();
    if expire > now {
        expire - now
    } else {
        Duration::ZERO
    }
}

pub fn push_unique_waker(wakers: &mut Vec<Waker>, waker: Waker) {
    if !wakers.iter().any(|old_waker| old_waker.will_wake(&waker)) {
        wakers.push(waker);
    }
}

pub fn push_unique_waker_by_key(wakers: &mut Vec<(usize, Waker)>, key: usize, waker: Waker) {
    if !wakers
        .iter()
        .any(|(old_key, old_waker)| *old_key == key && old_waker.will_wake(&waker))
    {
        wakers.push((key, waker));
    }
}

