/// shared between threads
pub(super) type SharedMut<T> = Arc<SpinLock<T>>;
pub(super) struct Shared<T>(PhantomData<T>);
impl<T> Shared<T> {
    pub fn new(data: T) -> SharedMut<T> {
        Arc::new(SpinLock::new(data))
