/// pending signals of a task
/// it stores signals that are pending to be handled.
/// note that: even if the signal is masked,
/// it will still be stored in the pending signals,
/// and will be handled when the signal is unmasked
pub struct SigManager {
    pub queue: VecDeque<SigInfo>, // pending signal queue that should be handled
    pub pending_set: SigSet,      // current pending signal set, used to avoid duplicate signals
    pub should_wake: SigSet,      // additional signals that should wake the task
    signalfd_wakers: Vec<(SigSet, Waker)>,
    signal_versions: [u64; NSIG],
}

impl SigManager {
    pub fn new() -> Self {
        Self {
            queue: VecDeque::new(),
            pending_set: SigSet::empty(),
            should_wake: SigSet::empty(),
            signalfd_wakers: Vec::new(),
            signal_versions: [0; NSIG],
        }
    }

    pub fn push(&mut self, sig_info: SigInfo) {
        let signal = sig_info.signal;
        if signal.is_realtime() || !self.pending_set.contains_signal(signal) {
            self.pending_set.enable(sig_info.signal);
            self.queue.push_back(sig_info);
            self.bump_signal_version(signal);
            self.wake_signalfd(signal);
        }
    }

    fn bump_signal_version(&mut self, signal: Signal) {
        let index = signal.into_sigaction_index();
        if index < NSIG {
            self.signal_versions[index] = self.signal_versions[index].wrapping_add(1);
        }
    }

    pub fn signalfd_generation(&self, mask: SigSet) -> u64 {
        let bits = mask.bits();
        let mut generation = 0u64;
        for index in 0..NSIG {
            if bits & (1usize << index) != 0 {
                generation = generation.wrapping_add(self.signal_versions[index]);
            }
        }
        generation
    }

    pub fn add_signalfd_waker(&mut self, mask: SigSet, waker: Waker) {
        self.signalfd_wakers
            .retain(|(old_mask, old_waker)| *old_mask != mask || !old_waker.will_wake(&waker));
        self.signalfd_wakers.push((mask, waker));
    }

    fn wake_signalfd(&mut self, signal: Signal) {
        let mut kept = Vec::new();
        for (mask, waker) in self.signalfd_wakers.drain(..) {
            if mask.contains_signal(signal) {
                waker.wake();
            } else {
                kept.push((mask, waker));
            }
        }
        self.signalfd_wakers = kept;
    }

