    if res.flag != 0 {
        let scause = MyScause::new(res.scause).bits();
        let stval = stval::read();
        let trap_type = get_trap_type(scause, stval);
        if trap_type.is_pagefault() {
            after_user_ptr();
            return Err(trap_type);
        } else {
            log::error!(
                "[check_read] read user ptr failed with unexpected trap {:?}",
                trap_type
            );
        }
    }
    after_user_ptr();
    Ok(())
}

unsafe fn check_write(ptr: usize) -> UserPtrResult {
    before_user_ptr();
    let res = __try_write_user(ptr);
    if res.flag != 0 {
        let scause = MyScause::new(res.scause).bits();
        let stval = stval::read();
        let trap_type = get_trap_type(scause, stval);
        if trap_type.is_pagefault() {
            after_user_ptr();
            return Err(trap_type);
        } else {
            log::error!(
                "[check_read] read user ptr failed with unexpected trap {:?}",
                trap_type
            );
        }
    }
    after_user_ptr();
    Ok(())
}

pub fn get_trap_type(scause: usize, stval: usize) -> TrapType {
    let scause = MyScause::new(scause);
    match scause.cause() {
        Trap::Exception(Exception::LoadFault) => TrapType::Unknown,
        Trap::Exception(Exception::UserEnvCall) => TrapType::Exception(ExceptionType::Syscall),
        Trap::Exception(Exception::StorePageFault) => TrapType::Exception(
            ExceptionType::PageFault(PageFaultType::StorePageFault(stval)),
        ),
        Trap::Exception(Exception::StoreFault) => TrapType::Exception(ExceptionType::PageFault(
            PageFaultType::StorePageFault(stval),
        )),
        Trap::Exception(Exception::InstructionPageFault) => TrapType::Exception(
            ExceptionType::PageFault(PageFaultType::InstructionPageFault(stval)),
        ),
        Trap::Exception(Exception::IllegalInstruction) => TrapType::Exception(
            ExceptionType::PageFault(PageFaultType::IllegalInstruction(stval)),
        ),
        Trap::Exception(Exception::LoadPageFault) => TrapType::Exception(ExceptionType::PageFault(
            PageFaultType::LoadPageFault(stval),
        )),
        Trap::Interrupt(int) => match int {
            Interrupt::SupervisorTimer => TrapType::Interrupt(InterruptType::Timer(1)),
            Interrupt::SupervisorExternal => {
                TrapType::Interrupt(InterruptType::SupervisorExternal(2))
            }
            Interrupt::SupervisorSoft => TrapType::Interrupt(InterruptType::SupervisorSoft(3)),
            _ => TrapType::Unknown,
        },
        _ => panic!("unknown trap type: {:?}", scause.cause()),
    }
}

#[inline(always)]
pub fn set_trap_entry(addr: usize) {
    unsafe { stvec::write(addr, TrapMode::Direct) };
}

fn set_kernel_trap_entry() {
    set_trap_entry(__kernel_trapvec as usize);
}
fn set_user_trap_entry() {
    set_trap_entry(__user_trapvec as usize);
}
fn set_ptr_entry() {
    set_trap_entry(__kernel_user_ptr_vec as usize);
}

pub fn trap_init() {
    set_kernel_trap_entry();
    enable_user_memory_access();
    enable_external_interrupt();
    enable_software_interrupt();
    enable_stimer_interrupt();
}

impl ArchTrap for RV64 {
    type TrapContext = super::context::TrapContext;
    /// init trap in a single hart
    /// note that it won't turn on global interrupt
    fn trap_init() {
        trap_init();
    }
    /// restore trap context, with freg handled as well
    fn trap_restore(cx: &mut TrapContext) {
        disable_interrupt();
        set_user_trap_entry();
        cx.freg_mut().restore();
        cx.sstatus().set_fs(FS::Clean);
        unsafe { __user_trapret(cx) };
        set_kernel_trap_entry();
        let fs = cx.sstatus().fs();
        cx.freg_mut().mark_save_if_needed(fs);
    }
    /// read exception pc
    fn read_epc() -> usize {
        sepc::read()
    }
    /// translate scause and stval to common TrapType
    fn read_trap_type(_cx: &mut TrapContext) -> TrapType {
        let scause = scause::read().bits();
        let stval = stval::read();
        get_trap_type(scause, stval)
    }
    /// try read user ptr
    fn check_read(addr: usize) -> UserPtrResult {
        unsafe { check_read(addr) }
    }
    /// try write user ptr
    fn check_write(addr: usize) -> UserPtrResult {
        unsafe { check_write(addr) }
    }
}

