fn add_metadata_block_device(fs_root: &Arc<dyn Dentry>, name: &str, major: u32, minor: u32) {
    if fs_root.get_child(name).is_some() {
        return;
    }
    info!("[fs] create /dev/{} block {}:{}", name, major, minor);
    let dentry = Arc::new(RamFsDentry::new(
        Some(fs_root.clone()),
        name,
        fs_root.super_block(),
    ))
    .into_dyn();
    let mode = InodeMode::BLOCK | InodeMode::from_bits(0o666).unwrap();
    let inode = Arc::new(SpecialInode::new(
        fs_root.super_block(),
        mode,
        DevT::new_encode_dev(major, minor),
    ));
    dentry.set_inode(inode);
    fs_root.add_child(dentry);
}

pub async fn init(fs_root: Arc<dyn Dentry>) -> SysResult<()> {
    assert_eq!(fs_root.name(), "dev");

    info!("[fs] create /dev/null");
    let null_dentry = Arc::new(NullDentry::new(
        Some(fs_root.clone()),
        "null",
        fs_root.super_block(),
    ));
    let null_inode = Arc::new(NullInode::new(fs_root.super_block()));
    null_dentry.into_dyn().set_inode(null_inode);
    fs_root.add_child(null_dentry);

    info!("[fs] create /dev/zero");
    let zero_dentry = Arc::new(zero::dentry::ZeroDentry::new(
        Some(fs_root.clone()),
        "zero",
        fs_root.super_block(),
    ));
    let zero_inode = Arc::new(zero::inode::ZeroInode::new(fs_root.super_block()));
    zero_dentry.into_dyn().set_inode(zero_inode);

