fn check_pending_signal(task: &Arc<Task>, mask: SigMask, phase: &str) -> Option<Errno> {
    let pcb = task.pcb();
    if pcb.signals.has_pending_signals(mask) {
        warn!(
            "[intable] TID{} get interrupted {}, mask {:?}, pending {:?}",
            task.tid(),
            phase,
            mask.debug_info_short(),
            pcb.signals.pending_set.debug_info_short()
        );
        drop(pcb);
        task.record_current_result_reg();
        task.tcb_mut().flags |= TaskFlags::TIF_SIGPENDING;
        Some(Errno::EINTR)
    } else {
        None
    }
}

fn leave_interruptible_sleep(task: &Arc<Task>) {
    task.tif_mut().remove(TaskFlags::TIF_WAIT_SLEEPING);
}

pin_project! {
    #[must_use = "futures do nothing unless you `.await` or poll them"]
    pub struct IntableFuture<'a, F> {
    task: &'a Arc<Task>,
    #[pin]
    fut: F,
    mask: SigMask,
    check_signal_before_poll: bool,
}
}

impl<F, T> Future for IntableFuture<'_, F>
where
    F: Future<Output = T>,
{
    type Output = SysResult<T>;
    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let this = self.project();
        let task = this.task;
        let mask = *this.mask;
        if *this.check_signal_before_poll {
            if let Some(errno) = check_pending_signal(task, mask, "before inner poll") {
                return Poll::Ready(Err(errno));
            }
        }

        match this.fut.poll(cx) {
            Poll::Ready(res) => {
                leave_interruptible_sleep(task);
                if *this.check_signal_before_poll {
                    if let Some(errno) = check_pending_signal(task, mask, "after inner ready") {
                        return Poll::Ready(Err(errno));
                    }
                }
                Poll::Ready(Ok(res))
            }
            Poll::Pending => {
                if let Some(errno) = check_pending_signal(task, mask, "after inner pending") {
                    leave_interruptible_sleep(task);
                    Poll::Ready(Err(errno))
